  const created = 'Created'.padEnd(14);
  const url = 'URL';

  return `  ${id} ${status} ${model} ${created} ${url}`;
}

/**
 * Format separator line
 */
function formatSeparator(): string {
  return '  ' + '-'.repeat(80);
}

