import { getSandbox, type Sandbox } from '@cloudflare/sandbox';
import type { Env } from '../../types.js';

const APP_DIR = '/root/app';
const BUILD_DIRS = ['dist', 'build', '.output', 'out'];

/**
 * Deploy built files to Cloudflare Pages using Wrangler
 * 
 * Note: Only destroys the sandbox on SUCCESS. On failure, the sandbox is kept alive
 * so the preview URL remains accessible as a fallback.
 */
export async function deployToPages(
  env: Env,
  jobId: string,
  sandboxNamespace: DurableObjectNamespace<Sandbox>,
  sandboxId: string
): Promise<string> {
  const sandbox = getSandbox(sandboxNamespace, sandboxId);
  const projectName = env.PAGES_PROJECT_NAME || 'nimbus';

  // Step 1: Find deploy path
  const deployPath = await findDeployPath(sandbox);

  // Step 2: Deploy using Wrangler
  // Set environment variables for wrangler
  // Use npx to ensure wrangler is found (it's installed globally but PATH might not include it)
  const wranglerCmd = [
    `export CLOUDFLARE_API_TOKEN="${env.CLOUDFLARE_API_TOKEN}"`,
    `export CLOUDFLARE_ACCOUNT_ID="${env.CLOUDFLARE_ACCOUNT_ID}"`,
    `npx wrangler pages deploy "${deployPath}" --project-name="${projectName}" --branch="${jobId}" --commit-message="Nimbus deployment: ${jobId}"`
  ].join(' && ');

  const result = await sandbox.exec(wranglerCmd);

  if (result.exitCode !== 0) {
    // Sanitize output to avoid leaking tokens in error messages
    const sanitizedOutput = (result.stderr || result.stdout)
      .replace(/CLOUDFLARE_API_TOKEN="[^"]*"/g, 'CLOUDFLARE_API_TOKEN="[REDACTED]"')
      .replace(/CLOUDFLARE_ACCOUNT_ID="[^"]*"/g, 'CLOUDFLARE_ACCOUNT_ID="[REDACTED]"');
    console.error('[Pages] Wrangler failed:', sanitizedOutput);
    // Don't destroy sandbox on failure - keep preview URL alive as fallback
    throw new Error(`Wrangler failed with exit code ${result.exitCode}`);
  }

  // Parse the deployment URL from wrangler output
  // Example output: "✨ Deployment complete! Take a peek over at https://abc123.project.pages.dev"
  const urlMatch = result.stdout.match(/https:\/\/[^\s]+\.pages\.dev/);
  if (!urlMatch) {
    console.error('[Pages] Could not parse URL from output:', result.stdout);
    // Don't destroy sandbox on failure - keep preview URL alive as fallback
    throw new Error('Could not parse deployment URL from wrangler output');
  }

  const deployedUrl = urlMatch[0];

  // Only destroy sandbox on successful deployment
  // (Preview URL no longer needed since we have a permanent Pages URL)
  try {
    await sandbox.destroy();
  } catch {
    // Ignore destruction errors
  }

  return deployedUrl;
}

async function findDeployPath(sandbox: ReturnType<typeof getSandbox>): Promise<string> {
  for (const dir of BUILD_DIRS) {
    const checkPath = `${APP_DIR}/${dir}`;
    const result = await sandbox.exec(`test -d ${checkPath} && echo "exists"`);
    if (result.stdout.includes('exists')) {
      return checkPath;
    }
  }
  return APP_DIR;
}

import { strict as assert } from 'assert';
import type { Env } from '../types.js';
import {
  DEFAULT_RUNTIME_FLAGS,
  getRuntimeFlagsFromEnv,
  loadRuntimeFlags,
  mergeRuntimeFlagOverrides,
  type RuntimeFlagRow,
} from './flags.js';

function createDb(rows: RuntimeFlagRow[] = [], errorMessage?: string): D1Database {
  return {
    prepare() {
      return {
        async all<T>() {
          if (errorMessage) {
            throw new Error(errorMessage);
          }

          return {
            results: rows as unknown as T[],
            success: true,
            meta: {
              duration: 0,
              rows_read: rows.length,
              rows_written: 0,
            },
          };
        },
      };
    },
  } as unknown as D1Database;
}

function createEnv(overrides: Partial<Env> = {}): Env {
  return {
    Sandbox: {} as DurableObjectNamespace<any>,
    DB: createDb(),
    OPENROUTER_API_KEY: 'test',
    DEFAULT_MODEL: 'anthropic/claude-sonnet-4',
    PREVIEW_HOSTNAME: 'example.com',
    PAGES_PROJECT_NAME: 'nimbus',
    CLOUDFLARE_API_TOKEN: 'token',
    CLOUDFLARE_ACCOUNT_ID: 'account',
    ...overrides,
  };
}

export async function runFlagsTests(): Promise<void> {
  {
    const env = createEnv();
    const resolved = getRuntimeFlagsFromEnv(env);
    assert.deepEqual(resolved, DEFAULT_RUNTIME_FLAGS);
  }

  {
    const env = createEnv({
      V2_ENABLED: 'true',
      MAX_ATTEMPTS: '0',
      ATTEMPT_TIMEOUT_MS: '45000',
      TOTAL_TIMEOUT_MS: '120000',
      LINT_BLOCKING: '1',
      TEST_BLOCKING: 'off',
      RAW_RETENTION_DAYS: '2',
      SUMMARY_RETENTION_DAYS: '8',
    });

    const resolved = getRuntimeFlagsFromEnv(env);

    assert.equal(resolved.v2Enabled, true);
    assert.equal(resolved.maxAttempts, 1);
    assert.equal(resolved.attemptTimeoutMs, 60000);
    assert.equal(resolved.totalTimeoutMs, 120000);
    assert.equal(resolved.lintBlocking, true);
    assert.equal(resolved.testBlocking, false);
    assert.equal(resolved.rawRetentionDays, 2);
    assert.equal(resolved.summaryRetentionDays, 8);
  }

  {
    const env = createEnv({
      ATTEMPT_TIMEOUT_MS: '900000',
      TOTAL_TIMEOUT_MS: '120000',
    });

    const resolved = getRuntimeFlagsFromEnv(env);
    assert.equal(resolved.attemptTimeoutMs, 900000);
    assert.equal(resolved.totalTimeoutMs, 900000);
  }

  {
    const base = DEFAULT_RUNTIME_FLAGS;
    const merged = mergeRuntimeFlagOverrides(base, [
      { key: 'max_attempts', value: '5' },
      { key: 'v2_enabled', value: 'true' },
      { key: 'unknown_key', value: 'ignored' },
    ]);

    assert.equal(merged.maxAttempts, 5);
    assert.equal(merged.v2Enabled, true);
    assert.equal(merged.rawRetentionDays, DEFAULT_RUNTIME_FLAGS.rawRetentionDays);
  }

  {
    const env = createEnv({
      V2_ENABLED: 'false',
      MAX_ATTEMPTS: '3',
      DB: createDb([
        { key: 'v2_enabled', value: 'true' },
        { key: 'max_attempts', value: '4' },
      ]),
    });

    const resolved = await loadRuntimeFlags(env);

    assert.equal(resolved.v2Enabled, true);
    assert.equal(resolved.maxAttempts, 4);
  }

  {
    const env = createEnv({
      V2_ENABLED: 'true',
      DB: createDb([], 'no such table: runtime_flags'),
    });

    const resolved = await loadRuntimeFlags(env);
    assert.equal(resolved.v2Enabled, true);
    assert.equal(resolved.maxAttempts, DEFAULT_RUNTIME_FLAGS.maxAttempts);
  }
}

