// Build metrics returned from worker
// NOTE: This interface is duplicated in packages/worker/src/types.ts - keep them in sync
export interface BuildMetrics {
  id: string;
  prompt: string;
  model: string;
  promptTokens: number;
  completionTokens: number;
  totalTokens: number;
  cost: number;
  llmLatencyMs: number;
  filesGenerated: number;
  linesOfCode: number;
  buildSuccess: boolean;
  deploySuccess: boolean;
  deployError?: string;
  installDurationMs: number;
  buildDurationMs: number;
  deployDurationMs: number;
  totalDurationMs: number;
  deployedUrl: string;
  startedAt: string;
  completedAt: string;
}

// SSE Event types (matching worker)
export type SSEEvent =
  | { type: 'job_created'; jobId: string }
  | { type: 'generating' }
  | { type: 'generated'; fileCount: number }
  | { type: 'scaffolding' }
  | { type: 'writing' }
  | { type: 'installing' }
  | { type: 'building' }
  | { type: 'starting' }
  | { type: 'preview_ready'; previewUrl: string }
  | { type: 'deploying' }
  | { type: 'deploy_warning'; message: string }
  | { type: 'deployed'; deployedUrl: string }
  | {
      type: 'complete';
      previewUrl: string;
      deployedUrl: string;
      isPreviewFallback?: boolean;
      metrics: BuildMetrics;
    }
  | { type: 'error'; message: string };

// Job status type
export type JobStatus = 'queued' | 'running' | 'completed' | 'failed' | 'cancelled';

// Job phase type
export type JobPhase =
  | 'queued'
  | 'planning'
  | 'generating'
  | 'building'
  | 'repairing'
  | 'validating'
  | 'deploying'
  | 'completed'
  | 'failed'
  | 'cancelled';

// Job response from API
export interface JobResponse {
  id: string;
  prompt: string;
  model: string;
  status: JobStatus;
  phase: JobPhase;
  createdAt: string;
  startedAt: string | null;
  completedAt: string | null;
  previewUrl: string | null;
  deployedUrl: string | null;
  errorMessage: string | null;
  fileCount: number | null;

  sourceType?: string | null;
  checkpointId?: string | null;
  commitSha?: string | null;
  sourceRef?: string | null;
  sourceBundleKey?: string | null;
  sourceBundleSha256?: string | null;
  sourceBundleBytes?: number | null;
}

// Job list item (lightweight)
export interface JobListItem {
  id: string;
  prompt: string;
  model: string;
  status: JobStatus;
  phase?: JobPhase;
  createdAt: string;
  deployedUrl: string | null;
}

// Jobs list response
export interface JobsListResponse {
  jobs: JobListItem[];
}

export interface CheckpointJobCreateResponse {
  jobId: string;
  status: JobStatus;
  phase: JobPhase;
  eventsUrl: string;
  jobUrl: string;
}

